mapper.select:
SELECT dataInfo.data_id,dataInfo.data_title,dictItem.item_text AS data_type,dataInfo.original, (SELECT GROUP_CONCAT( labelInfo.label_content ) FROM t_label_info labelInfo WHERE FIND_IN_SET(labelInfo.label_id,dataInfo.data_label)) AS data_label, (SELECT GROUP_CONCAT( userInfo.`name` ) FROM sys_user userInfo WHERE FIND_IN_SET( userInfo.user_id,dataInfo.partake_user)) AS partake_user, dataInfo.data_source,dataInfo.up_time,auditRecord.audit_status,auditRecord.audit_content FROM t_data_info dataInfo LEFT JOIN t_dict_item dictItem ON dataInfo.data_type = dictItem.item_id LEFT JOIN t_data_audit_record auditRecord ON dataInfo.data_id = auditRecord.data_id
AND dataInfo.user_id =#{dataInfo.userId}
AND dataInfo.data_type =#{dataInfo.dataType}
AND dataInfo.original =#{dataInfo.original}
AND dataInfo.data_title LIKE concat(concat('%',#{dataInfo.dataTitle}),'%')
AND dataInfo.data_source LIKE concat(concat('%',#{dataInfo.dataSource}),'%')
AND DATE_FORMAT(dataInfo.up_time, '%Y-%m-%d') >= DATE_FORMAT(#{dataInfo.upTimeBegin}, '%Y-%m-%d')
AND DATE_FORMAT(dataInfo.up_time, '%Y-%m-%d') <= DATE_FORMAT(#{dataInfo.upTimeEnd}, '%Y-%m-%d')
AND (
FIND_IN_SET(#{item.labelId},dataInfo.data_label)
)
AND FIND_IN_SET(#{dataInfo.partakeUser}, dataInfo.partake_user )
ORDER BY dataInfo.up_time DESC

