UPDATE t_data_record
SET like_num = like_num + 1
WHERE data_id=#{dataId}

UPDATE t_data_record
SET tap_num = tap_num + 1
WHERE data_id=#{dataId}

UPDATE t_data_record
SET collect_num = collect_num + 1
WHERE data_id=#{dataId}

UPDATE t_data_record
SET complete_num = complete_num + 1
WHERE data_id=#{dataId}
